#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y, Z; scanf("%lld %lld %lld", &X, &Y, &Z);
        long long total = 5LL*X + 10LL*Y;
        printf("%lld\n", total / Z);
    }
    return 0;
}

